const body = $json.body || $json;
const event = body.event || '';

if (event === 'meeting:agent-response') {
  const agent = body.agent || 'unknown';
  const content = body.content || '';
  const chatId = body.telegram?.chatId || '';
  const topic = body.topic || '';
  const round = body.round || 0;
  const maxRounds = body.maxRounds || 0;

  // Status messages (thinking indicators) — show as italic, no header
  if (agent === 'status') {
    return [{ json: { chatId, text: `_${content}_`, event } }];
  }

  // Format agent name nicely
  const agentDisplay = agent.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());

  // Build round indicator
  const roundTag = round ? `_Round ${round}/${maxRounds}_\n` : '';

  let text = `${roundTag}*${agentDisplay}:*\n\n${content}`;

  // Truncate for Telegram
  if (text.length > 4000) text = text.substring(0, 3990) + '...';

  return [{ json: { chatId, text, event } }];
}

if (event === 'meeting:ended') {
  const chatId = body.telegram?.chatId || '';
  const summary = body.summary || 'No summary';
  const duration = body.duration ? Math.round(body.duration / 60) + ' minutes' : 'unknown';

  let text = `*Meeting Ended*\n\n${summary}\n\n_Duration: ${duration} | ${body.messageCount || 0} messages_`;
  if (text.length > 4000) text = text.substring(0, 3990) + '...';

  return [{ json: { chatId, text, event } }];
}

return [{ json: { skip: true } }];
